const express = require('express');
const helmet = require('helmet');        // npm install helmet
const rateLimit = require('express-rate-limit'); // npm install express-rate-limit

const app = express();
const PORT = process.env.PORT || 3000;
const HOST = process.env.HOST || '127.0.0.1'; // Bind to localhost only

// --- Security Middleware ---
app.use(helmet()); // Sets secure HTTP headers (CSP, X-Frame-Options, etc.)
app.use(express.json({ limit: '10kb' })); // Body parsing with size limit to prevent payload attacks
app.use(express.urlencoded({ extended: true, limit: '10kb' }));

// --- Rate Limiting ---
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,                  // Limit each IP to 100 requests per window
  standardHeaders: true,
  legacyHeaders: false,
});
app.use(limiter);

// --- Routes ---
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res) => {
  // In a real app: sanitize/filter sensitive fields before returning
  const users = [
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ];
  res.json(users);
});

// --- 404 Handler ---
app.use((req, res) => {
  res.status(404).json({ error: 'Not found' });
});

// --- Global Error Handler ---
// Must have 4 parameters for Express to treat it as an error handler
app.use((err, req, res, next) => { // eslint-disable-line no-unused-vars
  console.error(`[Error] ${err.message}`); // Log internally, don't expose to client
  const status = err.status || err.statusCode || 500;
  res.status(status).json({
    error: process.env.NODE_ENV === 'production'
      ? 'An internal error occurred'
      : err.message, // Show details only in development
  });
});

// --- Server ---
const server = app.listen(PORT, HOST, () => {
  console.log(`Server running on ${HOST}:${PORT}`);
});

// Graceful shutdown
process.on('SIGTERM', () => {
  server.close(() => {
    console.log('Server shut down gracefully');
    process.exit(0);
  });
});

module.exports = app;
```

---

